/*
======================================================================
Design System
======================================================================
*/

:root {
    /* Color palette */
    --color-primary-teal: #00A0A8;
    --color-primary-indigo: #4F5F86;

    --color-secondary-lime: #8BC34A;
    --color-secondary-navy: #1B304A;

    --color-accent-gold: #C0B46A;

    --color-neutral-0: #FFFFFF;
    --color-neutral-50: #F5F7FA;
    --color-neutral-900: #333333;

    --color-success: #4CAF50;
    --color-error: #E53935;
    --color-warning: #FFB300;
    --color-info: #0288D1;

    /* Typography */
    --font-heading: 'Poppins', 'Helvetica', sans-serif;
    --font-body: 'Nunito', 'Arial', sans-serif;
    --font-code: 'Source Code Pro', monospace;

    --font-size-h1: 48px;
    --font-size-h2: 32px;
    --font-size-h3: 24px;
    --font-size-body: 16px;
    --font-size-small: 14px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (base unit: 8px) */
    --space-0-5: 4px;
    --space-1: 8px;
    --space-2: 16px;
    --space-3: 24px;
    --space-4: 32px;
    --space-5: 48px;
    --space-6: 64px;

    /* Layout bounds */
    --container-max-width: 1160px;

    /* Header / footer */
    --header-height-desktop: 96px;
    --footer-background: var(--color-secondary-navy);
}

/*
======================================================================
Global Resets and Base Styles
======================================================================
*/

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-neutral-900);
    background-color: var(--color-neutral-50);
    -webkit-font-smoothing: antialiased;
}

img {
    max-width: 100%;
    display: block;
}

a {
    color: inherit;
    text-decoration: none;
}

a:hover,
a:focus-visible {
    text-decoration: none;
}

ul,
ol {
    margin: 0;
    padding: 0;
    list-style: none;
}

button,
input,
textarea,
select {
    font-family: inherit;
}

.container {
    max-width: var(--container-max-width);
    margin-left: auto;
    margin-right: auto;
    padding-left: var(--space-4);
    padding-right: var(--space-4);
}

/*
======================================================================
Typography Helpers
======================================================================
*/

h1,
h2,
h3,
h4,
h5,
h6 {
    font-family: var(--font-heading);
    font-weight: var(--font-weight-semibold);
    letter-spacing: 0.16em;
    text-transform: uppercase;
    margin: 0 0 var(--space-3);
    color: var(--color-secondary-navy);
}

h1 { font-size: var(--font-size-h1); line-height: var(--line-height-tight); }

h2 { font-size: var(--font-size-h2); line-height: var(--line-height-tight); }

h3 { font-size: var(--font-size-h3); line-height: var(--line-height-tight); }

p {
    margin: 0 0 var(--space-2);
}

.small-text {
    font-size: var(--font-size-small);
}

/*
======================================================================
Header
======================================================================
*/

.site-header {
    position: relative;
    z-index: 100;
    background-color: var(--color-neutral-0);
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.04);
}

.header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    min-height: var(--header-height-desktop);
}

/* Brand area reflecting the original layout (logo left, stacked text) */

.brand {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-0-5);
    text-decoration: none;
}

.brand-mark {
    display: flex;
    flex-direction: column;
    line-height: 1.1;
}

.brand-main {
    font-family: var(--font-heading);
    font-weight: var(--font-weight-bold);
    font-size: 26px;
    color: var(--color-primary-teal);
}

.brand-sub {
    font-family: var(--font-heading);
    font-weight: var(--font-weight-regular);
    font-size: 14px;
    letter-spacing: 0.22em;
    text-transform: uppercase;
    color: var(--color-secondary-navy);
}

.brand-tagline {
    font-size: 11px;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    color: var(--color-secondary-navy);
    opacity: 0.8;
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
}

.brand-tagline-separator {
    opacity: 0.65;
}

/* Primary navigation (center/right, all caps, spacious) */

.primary-nav {
    font-family: var(--font-heading);
}

.nav-list {
    display: flex;
    align-items: center;
    gap: 32px;
}

.nav-item {
    position: relative;
}

.nav-link {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding-bottom: 4px;
    font-size: 13px;
    font-weight: var(--font-weight-semibold);
    letter-spacing: 0.16em;
    text-transform: uppercase;
    color: var(--color-primary-teal);
    border-bottom: 2px solid transparent;
    transition: color 0.2s ease, border-color 0.2s ease;
}

.nav-link:hover,
.nav-link:focus-visible {
    color: var(--color-secondary-navy);
    border-bottom-color: var(--color-primary-teal);
    outline: none;
}

.nav-link--active {
    border-bottom-color: var(--color-primary-teal);
}

/* Highlighted primary CTA in nav (mirroring TRAINING item) */

.nav-item--highlight .nav-link {
    color: var(--color-accent-gold);
}

.nav-item--highlight .nav-link:hover,
.nav-item--highlight .nav-link:focus-visible {
    color: var(--color-secondary-navy);
    border-bottom-color: var(--color-accent-gold);
}

/*
======================================================================
Main Layout
======================================================================
*/

.site-main {
    min-height: calc(100vh - var(--header-height-desktop));
    padding-top: var(--space-5);
    padding-bottom: var(--space-5);
}

/* Neutral background; individual pages can add their own hero sections
   (e.g., ink-cloud illustration) inside #content without changing this
   framework. */

/*
======================================================================
Footer
======================================================================
*/

.site-footer {
    background-color: var(--footer-background);
    color: var(--color-neutral-0);
    margin-top: var(--space-5);
}

.footer-top {
    padding-top: var(--space-5);
    padding-bottom: var(--space-4);
}

.footer-grid {
    display: grid;
    grid-template-columns: minmax(0, 2fr) repeat(3, minmax(0, 1fr));
    gap: var(--space-4);
    align-items: flex-start;
}

.footer-brand {
    max-width: 340px;
}

.footer-logo {
    font-family: var(--font-heading);
    font-weight: var(--font-weight-semibold);
    font-size: 20px;
    letter-spacing: 0.18em;
    text-transform: uppercase;
    margin-bottom: var(--space-2);
}

.footer-tagline {
    font-size: 14px;
    line-height: var(--line-height-normal);
    opacity: 0.9;
}

.footer-column {}

.footer-heading {
    font-family: var(--font-heading);
    font-weight: var(--font-weight-semibold);
    font-size: 13px;
    letter-spacing: 0.18em;
    text-transform: uppercase;
    margin: 0 0 var(--space-2);
    color: var(--color-neutral-0);
}

.footer-links {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.footer-link {
    font-size: 14px;
    line-height: var(--line-height-normal);
    color: rgba(255, 255, 255, 0.9);
    transition: color 0.2s ease, opacity 0.2s ease;
}

.footer-link:hover,
.footer-link:focus-visible {
    color: var(--color-accent-gold);
    opacity: 1;
    outline: none;
}

.footer-bottom {
    border-top: 1px solid rgba(255, 255, 255, 0.12);
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
}

.footer-bottom-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--space-2);
}

.footer-copy {
    margin: 0;
    font-size: 13px;
    opacity: 0.8;
}

/*
======================================================================
Utilities
======================================================================
*/

.visually-hidden {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    border: 0;
}

/*
======================================================================
Responsive Adjustments
======================================================================
*/

@media (max-width: 1024px) {
    .header-inner {
        align-items: flex-start;
        flex-direction: column;
        gap: var(--space-2);
        padding-top: var(--space-2);
        padding-bottom: var(--space-2);
    }

    .nav-list {
        flex-wrap: wrap;
        gap: 16px 24px;
    }

    .site-main {
        padding-top: var(--space-4);
        padding-bottom: var(--space-4);
    }

    .footer-grid {
        grid-template-columns: repeat(2, minmax(0, 1fr));
    }
}

@media (max-width: 720px) {
    .container {
        padding-left: var(--space-2);
        padding-right: var(--space-2);
    }

    .footer-grid {
        grid-template-columns: minmax(0, 1fr);
    }

    .footer-bottom-inner {
        flex-direction: column;
        align-items: flex-start;
    }

    .nav-list {
        flex-direction: column;
        align-items: flex-start;
    }
}
